sql:
SELECT director_name, genre_name
FROM directors, genres
WHERE genre_name IN ('Drama', 'Action', 'Sci-fi');

SELECT company_id, company_name, country, contact_email, established_year, ceo, headquarters, website, social_media_links
FROM companies
WHERE established_year > 2000;

SELECT w.writer_name, w.birth_year, w.gender
FROM writers w
WHERE w.nominations = (SELECT MAX(nominations) FROM writers);

SELECT 
  (SELECT COUNT(*) FROM actors) AS actor_count,
  (SELECT COUNT(*) FROM writers) AS writer_count;

SELECT d.director_id, d.director_name
FROM directors d
JOIN writers w ON d.director_id = w.writer_id;

SELECT a.actor_name, w.writer_name, d.director_name
FROM (
    SELECT actor_name FROM actors WHERE nationality = 'USA'
) a
CROSS JOIN (
    SELECT writer_name FROM writers WHERE nationality = 'USA'
) w
CROSS JOIN (
    SELECT director_name FROM directors WHERE nationality = 'USA'
) d;

SELECT genre_name 
FROM genres 
WHERE popularity = (SELECT MAX(popularity) FROM genres);
